                                                <p className="text-emerald-100/80 p-4 bg-emerald-500/10 rounded-lg border border-emerald-500/20 text-sm border-l-4 border-l-emerald-500">
                                                    {q.feedback?.betterSample || "Use the STAR method."}
                                                </p>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                </div>
            </div>
        </div>
    );
}

