'use client';

import React, { useEffect, useState } from 'react';

interface EmployabilityDashboardProps {
    token: string;
    onClose: () => void;
}

export default function EmployabilityDashboard({ token, onClose }: EmployabilityDashboardProps) {
    const [engineData, setEngineData] = useState<any>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [isEditing, setIsEditing] = useState(false);
    const [updateLoading, setUpdateLoading] = useState(false);

    useEffect(() => {
        const fetchAnalysis = async () => {
            try {
                const res = await fetch("http://localhost:5000/api/skills/analyze", {
                    headers: { "Authorization": `Bearer ${token}` }
                });
                const data = await res.json();

                if (!res.ok) {
                    throw new Error(data.message || 'Failed to fetch analysis');
                }

                setEngineData(data);
            } catch (err: unknown) {
                if (err instanceof Error) {
                    setError(err.message);
                } else {
                    setError('An unknown error occurred');
                }
            } finally {
                setLoading(false);
            }
        };
        fetchAnalysis();
    }, [token]);

    if (loading) {
        return (
            <div className="w-full h-full min-h-[600px] flex items-center justify-center bg-slate-900 border border-white/10 rounded-2xl">
                <div className="text-center">
                    <div className="w-16 h-16 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
                    <p className="text-white/60 animate-pulse">Running Intelligence Engine...</p>
                </div>
            </div>
        );
    }

    if (error || !engineData) {
        return (
            <div className="w-full h-full bg-slate-900 p-8 rounded-2xl border border-rose-500/30 text-center flex flex-col items-center justify-center">
                <span className="text-4xl mb-4">ΓÜá∩╕Å</span>
                <h3 className="text-xl font-bold text-white mb-2">Engine Unavailable</h3>
                <p className="text-white/60 mb-6 max-w-md">{error || "Data missing"}</p>
                <button onClick={onClose} className="px-6 py-2 bg-white/10 hover:bg-white/20 rounded-lg text-white transition-colors">Return</button>
            </div>
        );
    }

    const {
        overall_employability_score,
        employability_level,
        categorized_skill_indexes,
        job_eligibility_matching,
        strengths,
        improvement_areas,
        career_direction_recommendation,
        action_plan
    } = engineData;

    return (
        <div className="w-full h-full min-h-[700px] flex flex-col animate-fade-in bg-slate-900 border border-white/10 rounded-2xl shadow-2xl overflow-hidden relative">
            {/* Header */}
            <div className="p-6 border-b border-white/10 bg-gradient-to-r from-indigo-500/10 to-transparent flex justify-between items-center z-10">
                <div>
                    <h2 className="text-2xl font-bold text-white flex items-center gap-2">
                        <span>≡ƒºá</span> Employability Intelligence
                    </h2>
                    <p className="text-indigo-300 text-sm mt-1">AI-Powered Job Eligibility & Readiness</p>
                </div>
                <div className="flex gap-3">
                    <button
                        onClick={() => setIsEditing(!isEditing)}
                        className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${isEditing ? 'bg-indigo-600 text-white' : 'bg-white/10 text-white hover:bg-white/20'}`}
                    >
                        {isEditing ? 'Done Editing' : 'Γ£Å∩╕Å Override Scores'}
                    </button>
                    <button onClick={onClose} className="px-4 py-2 border border-white/10 rounded-lg text-white/50 hover:bg-white/5 transition-colors">Close Engine</button>
                </div>
            </div>

            <div className={`absolute top-0 left-0 w-full h-1 bg-indigo-500 transition-all duration-300 ${updateLoading ? 'opacity-100 animate-pulse' : 'opacity-0'}`}></div>

            <div className="p-6 flex-grow overflow-y-auto space-y-8 z-10">

                {/* Top Score Section */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <div className="col-span-1 bg-black/40 border border-indigo-500/30 rounded-2xl p-6 flex flex-col items-center justify-center text-center">
                        <div className="text-6xl font-black text-transparent bg-clip-text bg-gradient-to-br from-indigo-400 to-cyan-400 mb-2">
                            {overall_employability_score}
                        </div>
                        <h3 className="text-sm uppercase tracking-widest text-white/50 font-semibold mb-2">Overall Score</h3>
                        <div className={`px-4 py-1 rounded-full text-sm font-medium border ${overall_employability_score >= 80 ? 'bg-emerald-500/20 text-emerald-400 border-emerald-500/30' :
                            overall_employability_score >= 60 ? 'bg-amber-500/20 text-amber-400 border-amber-500/30' :
                                'bg-rose-500/20 text-rose-400 border-rose-500/30'
                            }`}>
                            {employability_level}
                        </div>
                    </div>

                    <div className="col-span-2 grid grid-cols-1 sm:grid-cols-2 gap-4">
                        <div className="bg-white/5 border border-white/5 rounded-xl p-5">
                            <h4 className="text-emerald-400 text-sm font-semibold uppercase mb-3 flex items-center gap-2"><span>≡ƒÜÇ</span> Top Strengths</h4>
                            <ul className="space-y-2">
                                {strengths.slice(0, 3).map((s: string, i: number) => (
                                    <li key={i} className="text-white/80 text-sm flex items-start gap-2">
                                        <span className="text-emerald-500 mt-0.5">ΓÇó</span> {s}
                                    </li>
                                ))}
                                {strengths.length === 0 && <p className="text-white/40 text-sm">Need more data.</p>}
                            </ul>
                        </div>
                        <div className="bg-white/5 border border-white/5 rounded-xl p-5">
                            <h4 className="text-rose-400 text-sm font-semibold uppercase mb-3 flex items-center gap-2"><span>≡ƒÄ»</span> Focus Areas</h4>
                            <ul className="space-y-2">
                                {improvement_areas.slice(0, 3).map((s: string, i: number) => (
                                    <li key={i} className="text-white/80 text-sm flex items-start gap-2">
                                        <span className="text-rose-500 mt-0.5">ΓÇó</span> {s}
                                    </li>
                                ))}
                                {improvement_areas.length === 0 && <p className="text-white/40 text-sm">No major gaps identified.</p>}
                            </ul>
                        </div>
                    </div>
                </div>

                {/* Categorized Indexes */}
                <div>
                    <div className="flex justify-between items-center mb-4">
                        <h3 className="text-xl font-bold text-white">Core Skill Indexes</h3>
                        {isEditing && <span className="text-xs text-indigo-400 animate-pulse">Live Editing Active</span>}
                    </div>

                    <div className="grid grid-cols-2 lg:grid-cols-5 gap-3">
                        {[
                            { id: 'communication_skills', title: 'Communication', data: categorized_skill_indexes.communication_skills, color: 'sky' },
                            { id: 'technical_skills', title: 'Technical', data: categorized_skill_indexes.technical_skills, color: 'fuchsia' },
                            { id: 'behavioral_skills', title: 'Behavioral', data: categorized_skill_indexes.behavioral_skills, color: 'amber' },
                            { id: 'cognitive_skills', title: 'Cognitive', data: categorized_skill_indexes.cognitive_skills, color: 'indigo' },
                            { id: 'professional_readiness', title: 'Professional', data: categorized_skill_indexes.professional_readiness, color: 'emerald' },
                        ].map((cat, idx) => (
                            <div key={idx} className={`bg-${cat.color}-500/5 border border-${cat.color}-500/20 rounded-xl p-4 flex flex-col items-center text-center transition-all ${isEditing ? 'ring-2 ring-indigo-500/50 transform scale-105' : ''}`}>

                                {!isEditing ? (
                                    <div className={`text-3xl font-bold text-${cat.color}-400 mb-2`}>{cat.data?.score || 0}</div>
                                ) : (
                                    <div className="w-full mb-3 flex flex-col items-center">
                                        <div className={`text-xl font-bold text-${cat.color}-400 mb-1`}>{cat.data?.score || 0}</div>
                                        <input
                                            type="range"
                                            min="0" max="100"
                                            value={cat.data?.score || 0}
                                            onChange={async (e) => {
                                                const newScore = e.target.value;
                                                // Optimistic local UI update could go here, but doing pure server-roundtrip for exact math
                                                setUpdateLoading(true);
                                                try {
                                                    const res = await fetch("http://localhost:5000/api/skills/override", {
                                                        method: "POST",
                                                        headers: {
                                                            "Content-Type": "application/json",
                                                            "Authorization": `Bearer ${token}`
                                                        },
                                                        body: JSON.stringify({ category: cat.id, newScore })
                                                    });
                                                    const updatedData = await res.json();
                                                    if (res.ok) setEngineData(updatedData);
                                                } catch (err) {
                                                    console.error(err);
                                                } finally {
                                                    setUpdateLoading(false);
                                                }
                                            }}
                                            className="w-full accent-indigo-500 h-1 bg-white/10 rounded-lg appearance-none cursor-pointer"
                                        />
                                    </div>
                                )}

                                <h4 className="text-white/70 text-xs font-semibold uppercase tracking-wider mb-2">{cat.title}</h4>
                                <span className={`text-[10px] px-2 py-0.5 rounded-full bg-${cat.color}-500/10 text-${cat.color}-300`}>
                                    {cat.data?.level || 'Unknown'}
                                </span>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Job Matches */}
                <div>
                    <div className="flex justify-between items-end mb-4">
                        <h3 className="text-xl font-bold text-white">Job Role Match Matrix</h3>
                        <span className="text-sm font-medium text-white/50">Readiness: {job_eligibility_matching.job_readiness_percentage}%</span>
                    </div>

                    <div className="space-y-4">
                        {/* Eligible Roles */}
                        {/* eslint-disable-next-line @typescript-eslint/no-explicit-any */}
                        {job_eligibility_matching.eligible_roles.map((role: any, idx: number) => (
                            <div key={`el-${idx}`} className="bg-emerald-500/10 border border-emerald-500/30 p-5 rounded-xl flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                                <div>
                                    <div className="flex items-center gap-2 mb-1">
                                        <h4 className="text-emerald-400 font-bold text-lg">{role.job_title}</h4>
                                        <span className="text-[10px] font-bold uppercase tracking-wider bg-emerald-500/20 text-emerald-300 px-2 py-0.5 rounded">{role.match_type}</span>
                                    </div>
                                    <p className="text-white/60 text-sm">{role.industry} ΓÇó Expected Salary: {role.salary_range_lpa}</p>
                                </div>
                                <div className="text-right">
                                    <div className="text-3xl font-black text-emerald-400">{role.eligibility_score}%</div>
                                    <p className="text-emerald-500/70 text-xs uppercase font-bold tracking-wider">Match</p>
                                </div>
                            </div>
                        ))}

                        {/* Moderate Roles */}
                        {/* eslint-disable-next-line @typescript-eslint/no-explicit-any */}
                        {job_eligibility_matching.moderate_match_roles.map((role: any, idx: number) => (
                            <div key={`mod-${idx}`} className="bg-amber-500/5 border border-amber-500/20 p-5 rounded-xl flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                                <div>
                                    <h4 className="text-amber-400 font-bold text-lg mb-1">{role.job_title}</h4>
                                    <p className="text-white/60 text-xs mt-1">Gap: {role.gap_reason}</p>
                                    <p className="text-amber-400/60 text-xs mt-1">Est. {role.improvement_plan_weeks} weeks to ready</p>
                                </div>
                                <div className="text-right">
                                    <div className="text-2xl font-bold text-amber-400">{role.eligibility_score}%</div>
                                </div>
                            </div>
                        ))}

                        {/* Low Roles */}
                        {/* eslint-disable-next-line @typescript-eslint/no-explicit-any */}
                        {job_eligibility_matching.low_match_roles.map((role: any, idx: number) => (
                            <div key={`low-${idx}`} className="bg-white/5 border border-white/5 p-4 rounded-xl flex justify-between items-center opacity-70">
                                <div>
                                    <h4 className="text-white/80 font-medium mb-1">{role.job_title}</h4>
                                    <p className="text-white/40 text-xs truncate max-w-sm">{role.gap_reason}</p>
                                </div>
                                <div className="text-white/50 font-bold">{role.eligibility_score}%</div>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Growth Path & Action Plan */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="bg-gradient-to-br from-indigo-900/40 to-black border border-indigo-500/20 p-6 rounded-2xl">
                        <h4 className="text-indigo-400 font-semibold mb-4">Recommended Career Path</h4>
                        <div className="space-y-3">
                            <p className="text-sm text-white/50"><span className="text-white/80 font-medium pb-1 block">Best Fit Domain</span> {career_direction_recommendation.best_fit_domain}</p>
                            <p className="text-sm text-white/50"><span className="text-white/80 font-medium pb-1 block">Growth Path</span> {career_direction_recommendation.suggested_career_path.join(' Γ₧ö ')}</p>
                            <p className="text-sm text-white/50"><span className="text-white/80 font-medium pb-1 block">Timeline to Top Role</span> ~ {career_direction_recommendation.estimated_time_to_top_role_months} months</p>
                        </div>
                    </div>

                    <div className="bg-gradient-to-br from-cyan-900/40 to-black border border-cyan-500/20 p-6 rounded-2xl">
                        <h4 className="text-cyan-400 font-semibold mb-4">Immediate Action Plan</h4>
                        <ul className="space-y-3">
                            {action_plan.immediate_steps.map((step: string, i: number) => (
                                <li key={i} className="flex gap-3 text-sm text-white/80 items-start">
                                    <span className="w-5 h-5 rounded bg-cyan-500/20 text-cyan-400 flex items-center justify-center flex-shrink-0 mt-0.5 text-xs">Γ£ô</span>
                                    <span>{step}</span>
                                </li>
                            ))}
                        </ul>
                    </div>
                </div>

            </div>
        </div>
    );
}
